// Convierte la URL de Google Drive en un enlace de descarga directa
// Ejemplo: https://drive.google.com/file/d/1abcXYZ/view?usp=sharing
// → https://drive.google.com/uc?export=download&id=1abcXYZ
const url = $json.URL || "";

let fileId = null;

let match = url.match(/\/d\/([a-zA-Z0-9_-]+)/);
if (match) {
  fileId = match[1];
}

if (!fileId) {
  match = url.match(/[?&]id=([a-zA-Z0-9_-]+)/);
  if (match) {
    fileId = match[1];
  }
}

return {
  fileId: fileId
};

// Clasifica un archivo suelto (no comprimido). Usa ruta real y tamano leido de disco.
function safeName(name) {
  let s = (name || "file").normalize("NFC");
  s = s.replace(/[\x00-\x1F]/g, "");
  s = s.replace(/[\[\]]/g, "");
  s = s.replace(/[:*?"<>|]/g, "_");
  s = s.replace(/\s+/g, "_").trim();
  return s || "file";
}

// datos reales del flujo (no del binario, que ya no viaja)
const cf = $('Calcular filename').item.json;
const filename = cf.filename || "file";
const ext = (cf.ext || "").toLowerCase();
const localPath = cf.localPath || ("/files/" + filename);
const filenameSafe = safeName(filename);
const nombre = filenameSafe.toLowerCase();

// tamano real leido por el nodo 'Tamano real (stat)' (su stdout)
const sizeBytes = Number(($json.stdout || "0").trim()) || 0;
const sizeGB = sizeBytes / (1024 ** 3);

let rutaDestino = "/_REVISAR/";
let tipo = "desconocido";

if (ext === "pkg") {
  rutaDestino = "/packages/";
  const esDLC = /dlc|addon|add-on/.test(nombre);
  if (sizeGB > 5) tipo = "juego";
  else if (sizeGB < 1 && esDLC) tipo = "dlc";
  else tipo = "update";
} else if (ext === "iso" || ext === "bin") {
  tipo = "iso";
  if (ext === "bin" || /ps1|psx/.test(nombre)) rutaDestino = "/PSXISO/";
  else if (/ps2/.test(nombre)) rutaDestino = "/PS2ISO/";
  else if (/psp/.test(nombre)) rutaDestino = "/PSPISO/";
  else rutaDestino = "/PS3ISO/";
} else if (ext === "rap") { rutaDestino = "/exdata/"; tipo = "licencia"; }
else if (ext === "sprx") { rutaDestino = "/plugins/"; tipo = "plugin"; }
else if (ext === "self" || ext === "edat") { rutaDestino = "/game/"; tipo = "instalado"; }
else if (ext === "") { rutaDestino = "/GAMES/"; tipo = "carpeta_jb"; }

return { json: { fileId: cf.fileId, filename, filenameSafe, ext, sizeBytes, sizeGB, tipo, rutaDestino, localPath } };

// Clasifica cada archivo extraido y usa la RUTA REAL que n8n ya conoce
function safeName(name) {
  let s = (name || "file").normalize("NFC");
  s = s.replace(/[\x00-\x1F]/g, "");
  s = s.replace(/[\[\]]/g, "");              // quitar corchetes
  s = s.replace(/[:*?"<>|]/g, "_");
  s = s.replace(/\s+/g, "_").trim();          // espacios -> guion bajo
  return s || "file";
}

const item = $input.item;
const data = item.binary?.data;
const filename = data?.fileName || 'file';        // nombre real del archivo extraido
const dir = data?.directory || '';                 // carpeta real donde quedo (n8n la sabe)
const filenameSafe = safeName(filename);
const nombre = filenameSafe.toLowerCase();
const ext = filename.includes('.') ? (filename.split('.').pop() || '').toLowerCase() : '';
const sizeBytes = Number(data?.fileSize || 0);
const sizeGB = sizeBytes / (1024 ** 3);

let rutaDestino = "/_REVISAR/";
let tipo = "desconocido";

if (ext === "pkg") {
  rutaDestino = "/packages/";
  const esDLC = /dlc|addon|add-on/.test(nombre);
  if (sizeGB > 5) tipo = "juego";
  else if (sizeGB < 1 && esDLC) tipo = "dlc";
  else tipo = "update";
} else if (ext === "iso" || ext === "bin") {
  tipo = "iso";
  if (ext === "bin" || /ps1|psx/.test(nombre)) rutaDestino = "/PSXISO/";
  else if (/ps2/.test(nombre)) rutaDestino = "/PS2ISO/";
  else if (/psp/.test(nombre)) rutaDestino = "/PSPISO/";
  else rutaDestino = "/PS3ISO/";
} else if (ext === "rap") { rutaDestino = "/exdata/"; tipo = "licencia"; }
else if (ext === "sprx") { rutaDestino = "/plugins/"; tipo = "plugin"; }
else if (ext === "self" || ext === "edat") { rutaDestino = "/game/"; tipo = "instalado"; }
else if (ext === "" || /ps3_game/.test(nombre)) { rutaDestino = "/GAMES/"; tipo = "carpeta_jb"; }

// localPath: ruta real en disco (puede tener espacios/corchetes; se maneja con comillas en lftp)
const localPath = dir ? (dir.replace(/\/$/, "") + "/" + filename) : ("/files/extracted/" + filename);

return { json: { ...$json, filename, filenameSafe, ext, sizeGB, tipo, rutaDestino, localPath }, binary: item.binary };

const fileId = $json.fileId || $('Code in JavaScript').item.json.fileId;
let filename = $json.name || ('file_' + fileId);
filename = filename.normalize("NFC")
  .replace(/[\x00-\x1F]/g, "").replace(/[\[\]]/g, "")
  .replace(/[:*?"<>|]/g, "_").replace(/\s+/g, "_").trim();
if (!filename) filename = "file";
const ext = filename.includes('.') ? (filename.split('.').pop()||'').toLowerCase() : '';
const localPath = "/files/" + filename;
return { json: { fileId, filename, ext, localPath } };

// Recupera los datos perdidos tras el Execute Command (cp)
const c = $('Calcular filename').item.json;
const stdout = $json.stdout || "";
return { json: {
  fileId: c.fileId,
  filename: c.filename,
  ext: c.ext,
  localPath: c.localPath,
  cpResult: stdout
} };
